const Template: Story<CalendarProps> = args => {
  const [selected, setSelected] = useState<Date | null>(new Date());
  return (
    <Calendar
      {...args}
      selected={selected}
      onChange={(date: Date) => {
        if (date) {
          setSelected(date);
        } else {
          setSelected(null);
        }
      }}
    />
  );
};

